const upsertControlUsageCounter = `-- name: UpsertControlUsageCounter :one
INSERT INTO control_usage_counters
  (edge_node_id, counter_epoch, environment_id, route_id, route_revision, direction, bytes, observed_at)
VALUES
  ($1, $2, $3, $4,
   $5, $6, $7, $8)
ON CONFLICT (edge_node_id, counter_epoch, environment_id, route_id, direction) DO UPDATE
SET bytes = greatest(control_usage_counters.bytes, EXCLUDED.bytes),
    route_revision = CASE WHEN EXCLUDED.bytes >= control_usage_counters.bytes THEN EXCLUDED.route_revision ELSE control_usage_counters.route_revision END,
    observed_at = greatest(control_usage_counters.observed_at, EXCLUDED.observed_at)
RETURNING edge_node_id, counter_epoch, environment_id, route_id, route_revision, direction, bytes, observed_at
`

type UpsertControlUsageCounterParams struct {
	EdgeNodeID    string
	CounterEpoch  string
	EnvironmentID string
	RouteID       string
	RouteRevision int64
	Direction     string
	Bytes         int64
	ObservedAt    time.Time
}

func (q *Queries) UpsertControlUsageCounter(ctx context.Context, arg UpsertControlUsageCounterParams) (ControlUsageCounter, error) {
	row := q.db.QueryRowContext(ctx, upsertControlUsageCounter,
		arg.EdgeNodeID,
		arg.CounterEpoch,
		arg.EnvironmentID,
		arg.RouteID,
		arg.RouteRevision,
		arg.Direction,
		arg.Bytes,
		arg.ObservedAt,
	)
	var i ControlUsageCounter
	err := row.Scan(
		&i.EdgeNodeID,
		&i.CounterEpoch,
		&i.EnvironmentID,
		&i.RouteID,
		&i.RouteRevision,
		&i.Direction,
		&i.Bytes,
		&i.ObservedAt,
	)
	return i, err
}
